```class Solution {
    public int reverseDegree(String s) {
        int result = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            result += (c - 'a' + 1) * (i + 1);
        }
        return result;
    }
}```
